+            '"' => {
+                buffer[out] = '\\';
+                buffer[out + 1] = '"';
+                out += 2;
+            },
+            '\\' => {
+                buffer[out] = '\\';
+                buffer[out + 1] = '\\';
+                out += 2;
+            },
+            '\n' => {
+                buffer[out] = '\\';
+                buffer[out + 1] = 'n';
+                out += 2;
+            },
+            '\r' => {
+                buffer[out] = '\\';
+                buffer[out + 1] = 'r';
+                out += 2;
+            },
+            '\t' => {
+                buffer[out] = '\\';
+                buffer[out + 1] = 't';
+                out += 2;
+            },
+            0x08 => {
+                buffer[out] = '\\';
+                buffer[out + 1] = 'b';
+                out += 2;
+            },
+            0x0C => {
+                buffer[out] = '\\';
+                buffer[out + 1] = 'f';
+                out += 2;
+            },
+            else => {
+                if (ch < 0x20) {
+                    const hex = "0123456789abcdef";
+                    buffer[out] = '\\';
+                    buffer[out + 1] = 'u';
+                    buffer[out + 2] = '0';
+                    buffer[out + 3] = '0';
+                    buffer[out + 4] = hex[(ch >> 4) & 0xF];
+                    buffer[out + 5] = hex[ch & 0xF];
+                    out += 6;
+                } else {
